from flask import Flask, request, jsonify
import face_recognition
import os
import numpy as np

app = Flask(__name__)

# Load known employee photos and encode them
known_face_encodings = []
known_face_names = []

def load_known_faces(directory):
    for filename in os.listdir(directory):
        if filename.endswith(".jpg") or filename.endswith(".png"):
            image_path = os.path.join(directory, filename)
            image = face_recognition.load_image_file(image_path)
            encoding = face_recognition.face_encodings(image)[0]
            known_face_encodings.append(encoding)
            known_face_names.append(filename.split('.')[0])

load_known_faces("employee_photos")

@app.route('/recognize', methods=['POST'])
def recognize():
    if 'image' not in request.files:
        return jsonify({"error": "No image provided"}), 400

    file = request.files['image']
    if file.filename == '':
        return jsonify({"error": "No selected file"}), 400

    if file and allowed_file(file.filename):
        image_bytes = file.read()
        unknown_image = face_recognition.load_image_file(image_bytes)
        unknown_face_encodings = face_recognition.face_encodings(unknown_image)

        if not unknown_face_encodings:
            return jsonify({"error": "No faces found in the image"}), 400

        results = []
        for encoding in unknown_face_encodings:
            matches = face_recognition.compare_faces(known_face_encodings, encoding)
            name = "Unknown"
            confidence_scores = [1.0 if match else 0.0 for match in matches]
            total_confidence = sum(confidence_scores) / len(confidence_scores)

            if True in matches:
                first_match_index = matches.index(True)
                name = known_face_names[first_match_index]

            results.append({
                "name": name,
                "confidence_scores": confidence_scores,
                "total_confidence": total_confidence
            })

        return jsonify(results), 200

    else:
        return jsonify({"error": "Invalid file type"}), 400

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in {'jpg', 'png'}

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)